const VECTOR_SIZE = 1536;

function neutralVector() {
  return new Array(VECTOR_SIZE).fill(0);
}

function clean(value) {
  if (!value) return "";

  if (typeof value === "string") {
    return value.trim();
  }

  if (Array.isArray(value)) {
    return value
      .flatMap(v => {
        if (!v) return [];
        if (typeof v === "string") return v;
        if (typeof v === "object") return Object.values(v);
        return [];
      })
      .filter(Boolean)
      .join(" ")
      .trim();
  }

  if (typeof value === "object") {
    return Object.values(value)
      .flat()
      .filter(Boolean)
      .join(" ")
      .trim();
  }

  return "";
}

// Se texto estiver vazio → retorna vetor neutro
function safeVector(text) {
  if (!text || typeof text !== "string" || text.trim().length === 0) {
    return neutralVector();
  }
  return text; // mantém texto para embedding posterior
}

return items.map(item => {
  const fp = item.json.full_profile || {};

  const produtosRaw = fp.ofertas?.produtos || [];
  const servicosRaw = fp.ofertas?.servicos || [];
  const descricao = fp.identidade?.descricao || "";
  const publico = fp.classificacao?.publico_alvo || "";
  const clientes = fp.reputacao?.lista_clientes || [];
  const certificacoes = fp.reputacao?.certificacoes || [];

  const produtosClean = clean(produtosRaw);
  const servicosClean = clean(servicosRaw);
  const descricaoClean = clean(descricao);
  const publicoClean = clean(publico);
  const clientesClean = clean(clientes);

  return {
    json: {

      // =====================
      // VETORES
      // =====================

      "vetor.servicos": safeVector(servicosClean),
      "vetor.produtos": safeVector(produtosClean),
      "vetor.descricao": safeVector(descricaoClean),
      "vetor.publico": safeVector(publicoClean),
      "vetor.clientes": safeVector(clientesClean),

      // =====================
      // PAYLOAD
      // =====================

      "payload.produtos": produtosClean,
      "payload.servicos": servicosClean,
      "payload.descricao": descricaoClean,
      "payload.publico": publicoClean,
      "payload.clientes": clientesClean,
      "payload.certificacoes": clean(certificacoes),
      "payload.uf": clean(fp.identidade?.uf),
      "payload.cnpj": clean(fp.identidade?.cnpj),
      "payload.cidade": clean(fp.identidade?.municipio),
      "payload.nome_empresa": clean(fp.identidade?.nome_empresa),
      "payload.modelo_negocio": clean(fp.classificacao?.modelo_negocio),
      "payload.industria": clean(fp.classificacao?.industria)

    }
  };
});

